1	export type Cell = [number, number]; // [x, y]
2	
3	type CellKey = string;
4	
5	const toKey = ([x, y]: Cell): CellKey => `${x},${y}`;
6	const fromKey = (key: CellKey): Cell => key.split(",").map(Number) as Cell;
7	
8	const NEIGHBOR_OFFSETS: Cell[] = [
9	  [-1, -1], [0, -1], [1, -1],
10	  [-1, 0], [1, 0],
11	  [-1, 1], [0, 1], [1, 1],
12	];
13	
14	const NEIGHBORS_TO_SURVIVE = 2;
15	const NEIGHBORS_TO_BIRTH = 3;
16	
17	const isAliveNextGeneration = (isAlive: boolean, liveNeighbors: number): boolean =>
18	  liveNeighbors === NEIGHBORS_TO_BIRTH ||
19	  (isAlive && liveNeighbors === NEIGHBORS_TO_SURVIVE);
20	
21	export function nextGeneration(cells: Cell[]): Cell[] {
22	  const living = new Set(cells.map(toKey));
23	  const neighborCounts = new Map<CellKey, number>();
24	
25	  for (const [x, y] of cells) {
26	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
27	      const key = toKey([x + dx, y + dy]);
28	      neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
29	    }
30	  }
31	
32	  const next: Cell[] = [];
33	  for (const [key, liveNeighbors] of neighborCounts) {
34	    if (isAliveNextGeneration(living.has(key), liveNeighbors)) {
35	      next.push(fromKey(key));
36	    }
37	  }
38	  return next;
39	}
