1	import { describe, it, expect } from "vitest";
2	import { nextGeneration, type Cell } from "./game-of-life.js";
3	import { sortCells } from "./test-helpers.js";
4	
5	describe("Game of Life - Next Generation", () => {
6	  it("an empty grid stays empty — [] → []", () => {
7	    expect(nextGeneration([])).toEqual([]);
8	  });
9	  it("a single live cell dies (0 neighbors) — [(0,0)] → []", () => {
10	    expect(nextGeneration([[0, 0]])).toEqual([]);
11	  });
12	  it("Rule 1 underpopulation: two adjacent cells both die — [(0,1),(1,1)] → []", () => {
13	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
14	  });
15	  it("Rule 3 overpopulation: center cell with 4 live neighbors dies — ### / .#. / ### → #.# / #.# / #.#", () => {
16	    const gen0: Cell[] = [
17	      [0, 0], [1, 0], [2, 0],
18	      [1, 1],
19	      [0, 2], [1, 2], [2, 2],
20	    ];
21	    const result = nextGeneration(gen0);
22	    // Center (1,1) has 4 live neighbors → dies (Rule 3).
23	    expect(result).not.toContainEqual([1, 1]);
24	    // Full next generation per the rules (the prompt's 3×3 sketch is
25	    // illustrative only; cells are also born just outside that window).
26	    expect(sortCells(result)).toEqual(
27	      sortCells([
28	        [0, 0], [2, 0],
29	        [1, -1], [1, 3],
30	        [1, 0], [1, 2],
31	        [0, 2], [2, 2],
32	      ]),
33	    );
34	  });
35	  it("Rule 4 reproduction: a dead cell with exactly 3 live neighbors becomes alive — (1,1) born from [(0,0),(1,0),(0,1)]", () => {
36	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
37	    expect(result).toContainEqual([1, 1]);
38	  });
39	  it("Rule 2 survival: a live cell with 2 live neighbors lives on — (1,0) survives in ### / ... / .#.", () => {
40	    // Gen 0: (1,0) is alive with exactly 2 live neighbors (0,0) and (2,0).
41	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 2]]);
42	    expect(result).toContainEqual([1, 0]);
43	  });
44	  it("Block still life is unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
45	    const block: Cell[] = [[0, 0], [1, 0], [0, 1], [1, 1]];
46	    expect(sortCells(nextGeneration(block))).toEqual(sortCells(block));
47	  });
48	  it("Blinker oscillates — vertical [(0,0),(0,1),(0,2)] → horizontal [(-1,1),(0,1),(1,1)]", () => {
49	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
50	    expect(sortCells(result)).toEqual(sortCells([[-1, 1], [0, 1], [1, 1]]));
51	  });
